#include<bits/stdc++.h>
using namespace std;
int main() {
	int ans = 0;
	int n, m, a[100005], i = 1, j = 1, t[100005] = {0}, l = 0, v[100005] = {0};
	cin >> n >> m;
	for (int i = 1; i <= n; i++) cin >> a[i];
	while (i < n) {
		while (ans < m && j<=n) {
			if (!t[a[j]]) {
				ans++;
				t[a[j]]++;
			} else {
				t[a[j]]++;
			}
			j++;
		}
		while (ans >= m && i<=n) {
			if (t[a[i]] == 1) {
				ans--;
				t[a[i]]--;
			} else {
				t[a[i]]--;
			}
			i++;
		}
		l++;
		v[i-1]=1;
		for (int k = i; k <= j-1; k++) {
			v[k] = 1;
			if (t[a[k]] == 1) {
				ans--;
				t[a[k]]--;
			} else {
				t[a[k]]--;
			}
		}
		i = j + 1;
		j++;

	}
	for (int i = 1; i <= n; i++) {
		if (!v[i]) {
			if (!t[a[i]]) {
				ans++;
				t[a[i]]++;
			} else {
				t[a[i]]++;
			}

		}
	}
	if (ans >= m) l++;
	cout << l;
}
